#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long prev, cur; scanf("%lld",&prev);
        int possible = 0;
        for(int i=1;i<N;i++){
            scanf("%lld",&cur);
            if(prev < cur) possible = 1;
            prev = cur;
        }
        printf(possible?"Yes\n":"No\n");
    }
    return 0;
}

